import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import API from '../api/axios';
import { useAuth } from '../context/AuthContext';

export default function Login() {
  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async () => {
    if (!form.email || !form.password) return toast.error('Fill all fields');
    setLoading(true);
    try {
      const res = await API.post('/auth/login', form);
      login(res.data.user, res.data.token);
      toast.success(`Welcome back, ${res.data.user.name}!`);
      if (res.data.user.role === 'admin') navigate('/admin');
      else if (res.data.user.role === 'provider') navigate('/dashboard');
      else navigate('/');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    }
    setLoading(false);
  };

  return (
    <div style={{
      minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center',
      background: 'radial-gradient(ellipse at center, rgb(45, 145, 232) 0%, #9191ff 70%)',
      padding: '20px'
    }}>
      <div className="glass animate-in" style={{ width: '100%', maxWidth: '420px', padding: '48px 40px' }}>
        <div style={{ textAlign: 'center', marginBottom: '36px' }}>
          <div style={{ fontSize: '48px', marginBottom: '12px' }}>👋</div>
          <h2 style={{ fontSize: '28px', fontWeight: 800 }}>Welcome Back</h2>
          <p style={{ color: 'rgb(255, 73, 73)', marginTop: '6px' }}>Sign in to your account</p>
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
          <div>
            <label style={{ fontSize: '13px', color: 'rgba(255, 87, 87, 0.98)', marginBottom: '6px', display: 'block' }}>Email Address</label>
            <input className="input-field" placeholder="you@example.com" type="email"
              onChange={e => setForm({ ...form, email: e.target.value })} />
          </div>
          <div>
            <label style={{ fontSize: '13px', color: 'rgba(255,255,255,0.6)', marginBottom: '6px', display: 'block' }}>Password</label>
            <input className="input-field" placeholder="••••••••" type="password"
              onChange={e => setForm({ ...form, password: e.target.value })}
              onKeyDown={e => e.key === 'Enter' && handleSubmit()} />
          </div>

          <button className="btn-primary" onClick={handleSubmit} disabled={loading}
            style={{ width: '100%', padding: '14px', fontSize: '15px', marginTop: '8px', opacity: loading ? 0.7 : 1 }}>
            {loading ? '⏳ Signing in...' : 'Sign In →'}
          </button>
        </div>

        <div style={{ textAlign: 'center', marginTop: '24px' }}>
          <p style={{ color: 'rgb(239, 70, 70)', fontSize: '14px' }}>
            No account? <Link to="/register" style={{ color: '#a855f7', fontWeight: 600, textDecoration: 'none' }}>Create one free</Link>
          </p>
        </div>

        {/* Demo credentials hint */}
        <div style={{ marginTop: '24px', padding: '14px', borderRadius: '10px', background: 'rgba(99,102,241,0.08)', border: '1px solid rgba(99,102,241,0.15)' }}>
          <p style={{ fontSize: '12px', color: 'rgba(227, 73, 73, 0.97)', textAlign: 'center' }}>
            🛡️ Admin: <span style={{ color: '#8f3fd9' }}>admin@appointease.com / Admin@123</span>
          </p>
        </div>
      </div>
    </div>
  );
}
